// scrape.js
const { chromium } = require('playwright');

(async () => {
  // ① Launch a headless browser
  const browser = await chromium.launch();
  const page = await browser.newPage();

  // ② Navigate to the page you want to scrape
  await page.goto('https://news.ycombinator.com/news');

  // ③ Grab all the rows that contain a story
  // Each story is inside a <tr class="athing"> element
  const rows = await page.$$('tr.athing');

  // ④ Extract title and URL for each story
  const stories = await Promise.all(rows.map(async (row) => {
    // The title is inside a <a class="storylink">
    const titleHandle = await row.$('td.title > a.storylink');
    const title = await titleHandle.innerText();
    const url   = await titleHandle.getAttribute('href');

    return { title, url };
  }));

  // ⑤ Print the results
  console.log('Hacker News Headlines:');
  stories.forEach((s, i) => {
    console.log(`${i + 1}. ${s.title}`);
    console.log(`   → ${s.url}`);
  });

  // ⑥ Clean up
  await browser.close();
})();

